@startuml
skinparam packageStyle rectangle

package "persistence" {
    folder server <<entity>> {
        class Server #C0FFEE<<Class>> {
            seq : Integer
            name : String
            ip : String
        }
    }

    folder author <<entity>> {
        class Author #C0FFEE<<Class>> {
            seq : Integer
            name : String
            regDate : Date
        }
    }

    folder member <<entity>> {
        class Member #C0FFEE<<Class>> {
            seq : Integer
            id : String
            password : String
            name : String
            type : MemberType
        }

        enum MemberType #F8CECC<<Enumeration>> {
            USER,ADMIN
        }
    }

    folder book <<entity>> {
        abstract Book #D4E1F5<<Abstract Class>> {
            seq : Integer
            title : String
            author : Author
            regDate : Date
            expireDate : Date
            register : Member
            descriptionUrl : String
            tags : List<Tag>
        }

        Tag #C0FFEE<<Class>> {
            seq : Integer
            value : String
        }

        ScanBook #C0FFEE<<Class>> extends Book {
            fileName : String
            fileHash : String
            path : String
            server : Server
            size : Integer
        }

        RidiBook #C0FFEE<<Class>> extends Book {
            url : String
            ridiUserId : String
        }
    }
}
@enduml
